onClick:
{{
appsmith.store.accionSuplidor === "MODIFICAR"
&& inpClave.text !== ObtenerClaveSistema.data[0].valor_configuracion

? showAlert(
    "Contraseña incorrecta.",
    "error"
)

: (
    appsmith.store.accionSuplidor === "MODIFICAR"

        ? ModificarSuplidor.run()

        : GuardarSuplidor.run()
)

.then(() =>

    showAlert(
        appsmith.store.accionSuplidor === "MODIFICAR"
            ? "Suplidor modificado correctamente."
            : "Suplidor creado correctamente.",
        "success"
    )

)

.then(() =>

    storeValue(
        "accionSuplidor",
        "CREAR"
    )

)

.then(() =>

    resetWidget(
        "cntAgregarSuplidor",
        true
    )

)

.catch((error) =>

    showAlert(
        error.message,
        "error"
    )

)
}}

tooltip:
{{
appsmith.store.accionSuplidor === "MODIFICAR"
    ? "Modo Modificar. Los cambios se guardarán sobre el suplidor seleccionado."
    : "Crear un nuevo suplidor."
}}
